"""
MKT Context Commentary — Exodus chapters 1–3
Run: python3 scripts/zc-context-exodus-1-3-fill.py

Source data used:
- data/interlinear/exodus.json
- data/translation/draft/mediating/exodus.json

Key decisions in this range:
- Pharaoh identity: early date (Thutmose I, ca. 1526 BC) and late date (Ramesses II, ca. 1279-1213 BC) noted where relevant; the text is not treated as resolving the debate
- Goshen identified as eastern Nile delta / Wadi Tumilat region
- Egyptian names: Moses (msy = born of), Pharaoh's daughter unnamed here (later tradition: Thermuthis, Bithiah/1 Chr 4:18)
- The midwives' civil disobedience treated as historically grounded, not idealized
- The divine name YHWH: the Exodus as the context in which the name is made known (Ex 6:3)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

EXODUS = {
"1": {
"1": "<p>The opening phrase — <em>ve-eleh shemot</em>, 'and these are the names' — connects Exodus directly to Genesis (Gen 46:8 opens the same list with <em>ve-eleh shemot</em>). The 'and' signals narrative continuity, not a new story. The sons of Israel who came to Egypt are the same individuals whose stories ended in Genesis; Exodus begins where Genesis left off. The list serves as a genealogical bridge, reminding the reader that what follows is not a new divine initiative but the continuation of the covenant made with the patriarchs.</p>",
"2": "<p>The six sons of Leah named first (Reuben, Simeon, Levi, Judah, Issachar, Zebulun), then Rachel's sons (Benjamin — Joseph is not listed because he was already in Egypt, cf. v.5), then the sons of the concubines (Dan, Naphtali, Gad, Asher). The listing order approximates Gen 35:23-26 but adapts it. This is not a complete genealogy (wives and daughters are not listed) but a patriarchal inventory — the seed of the nation that will be formed at Sinai.</p>",
"3": "<p>Issachar, Zebulun — two of Leah's sons. The tribal names in the list anticipate the twelve-tribe structure that will be organized at Sinai and assigned territories in Canaan. The reader of the completed Torah knows each name carries the weight of a whole tribe's history; the text names them individually before the mass of 'the people' obscures the personal.</p>",
"4": "<p>Benjamin (son of Rachel, born in Canaan in Gen 35:18) and the four sons of the concubines close the list. The ordering of the twelve reflects the complex family hierarchy of Jacob's household — a social structure of competing matrilineal claims that will later surface in tribal rivalries throughout the Deuteronomistic history.</p>",
"5": "<p>Seventy persons descended from Jacob — a formulaic total (see also Gen 46:27 and Deut 10:22 which give the same number, though with slightly different counting methods). Seventy is a significant round number in ANE thought, representing completeness (70 elders of Israel in Ex 24:1, 70 nations in the Table of Nations Gen 10). The family of Jacob in Egypt is a complete, bounded unit — a nation-in-seed, not yet a nation in fact.</p>",
"6": "<p>Joseph and all his brothers and all that generation died — the bridge between the patriarchal era and the slavery era is removed. The connection to the Egyptian court that protected Israel (Joseph's role in Gen 41-50) no longer operates. This death notice marks the end of an era and sets the conditions for the persecution to follow: without a Joseph in the palace, there is no advocate for the Hebrews.</p>",
"7": "<p>The multiplication of Israel in Egypt is described with six verbs of growth — language that echoes the creation mandate of Gen 1:28 (<em>paru urvu</em> = be fruitful and multiply). The Israelites in Goshen live out the Adamic commission: fruitful, multiplying, filling the land. Historically, the Goshen region (eastern Nile delta, modern Wadi Tumilat) was fertile agricultural land suitable for pastoralists, and Egyptian records document Semitic populations in this region during the New Kingdom period.</p>",
"8": "<p>A new king who did not know Joseph — the phrase <em>asher lo-yada et-Yosef</em> signals either a dynasty change or a deliberate political distancing from the previous administration. The most likely historical scenario: the Hyksos (Semitic rulers of northern Egypt, ca. 1650-1550 BC) were expelled by the native Egyptian 18th Dynasty, which had reason to view the Semitic population of Goshen with suspicion. Alternatively, under the late-date theory, Ramesses II (ca. 1279-1213 BC) initiated the large building projects at Pi-Ramesse. Either scenario produces a Pharaoh hostile to the Israelite presence.</p>",
"9": "<p>Pharaoh frames the Israelites as a demographic security threat: 'more numerous and mightier than we.' Whether or not this was statistically true, the perception drove policy. Ancient Near Eastern rulers regularly used population politics — relocating, enslaving, or eliminating groups perceived as threats. The fear articulated in v.10 (that the Israelites might join an enemy and 'go up out of the land') reflects the standard anxiety of a state with a large, unassimilated ethnic minority near its northern border.</p>",
"10": "<p>'Let us deal shrewdly with them' — the word for dealing shrewdly (<em>nitchakemah</em>) is ironic: human wisdom applied against the covenant people will ultimately prove foolish (cf. 1 Cor 1:27). Pharaoh's strategy is to suppress demographic growth through forced labor. The phrase 'go up out of the land' anticipates the exodus itself — Pharaoh's fear will become precisely the reality he was trying to prevent. Egyptian records document the use of Asiatic foreigners as state labor, particularly in large construction projects.</p>",
"11": "<p>Pithom and Rameses are the two store cities (or supply depots — <em>arei miskenot</em>, not palace cities) built by the Israelite corvée labor. Pi-Ramesse (Per-Ramesses, House of Ramesses) is identified with modern Qantir/Tell el-Dab'a in the eastern Nile delta — archaeological excavations have uncovered extensive mudbrick construction there, including a large royal capital from the reign of Ramesses II. Pithom is identified with Tell er-Retabeh or Tell el-Maskhuta in Wadi Tumilat. The forced labor system (corvée) was a standard feature of ancient Near Eastern state building — Papyrus Anastasi III documents Semitic workers assigned daily brick quotas under Egyptian overseers.</p>",
"12": "<p>The Egyptians are in dread of the Israelites — <em>vayaqutzu mipnei benei Yisrael</em>, they felt sick/loathing at the sight of them. The persecution paradox is stated starkly: the more they were afflicted, the more they multiplied. This counterintuitive dynamic recurs throughout biblical history (Acts 8:1-4: persecution of the early church scatters and thereby spreads it). The Egyptian oppression cannot suppress what God is doing — the divine blessing on the seed of Abraham is not extinguishable by human force.</p>",
"13": "<p>The intensification of labor — <em>abodah parach</em>, crushing/harsh labor. This exact phrase later appears as the legal norm in Lev 25:43, 46, 53 where Israel is commanded <em>not</em> to rule over fellow Israelites with crushing labor. The Exodus experience becomes the ethical foundation of Israel's own labor law: you know what it is to be worked to breaking point; do not do this to others.</p>",
"14": "<p>Mortar, brick, and all field labor — mudbrick production was the dominant labor-intensive construction material in ancient Egypt. Workers mixed Nile mud with straw (a binder that prevented cracking) and shaped it in wooden molds. Bricks were sun-dried rather than kiln-fired. The Anastasi papyri from the 19th Dynasty describe foreign workers making bricks, with overseers recording daily production quotas. The 'bitter' labor (<em>vayemareru</em>) uses the same root as Marah (the bitter water, Ex 15:23) and the bitter herbs of the Passover meal — the Exodus liturgy encodes this bitterness into the annual memorial feast.</p>",
"15": "<p>Shiphrah and Puah — both are Semitic names, attested in the historical record. An Egyptian slave list from ca. 1750 BC (Brooklyn Papyrus) contains the name Shiphrah among Semitic servants in Egypt. This historical grounding is significant: the narrative names real women who performed a real act of civil disobedience. Their names are preserved while Pharaoh — the most powerful figure on earth — remains nameless throughout the Exodus narrative. The one who tries to destroy Israel is unnamed; the women who preserved Israel are named.</p>",
"16": "<p>The birthstool (<em>obnayim</em>) was the delivery stone or stool on which a woman in labor knelt or sat during childbirth. Egyptian art and texts depict women giving birth in a kneeling or squatting position supported by two stones or a birth chair. The midwives' role was to attend the birth and receive the infant. Pharaoh's instruction — kill the boys at the moment of birth — required the midwives to be agents of infanticide in the most vulnerable moment of human life, exploiting their position of trust.</p>",
"17": "<p>The midwives feared God (<em>vayyire'u hamyaledot et-ha'Elohim</em>) — the first recorded act of principled civil disobedience in the Bible. Their theological conviction — fear of God superseding fear of the state — is the basis for their refusal. This pattern (God over Pharaoh, God over Nebuchadnezzar, God over the Sanhedrin) runs through the entire biblical narrative and into the NT (Acts 5:29: 'We must obey God rather than human beings'). The midwives did not theorize their disobedience; they simply refused to do what was wrong.</p>",
"18": "<p>Pharaoh summons the midwives to account — the most powerful man in the ancient world interrogating two women about why they did not carry out his genocidal decree. The power asymmetry is enormous; the narrative's sympathies are entirely with the midwives. Their answer (v.19) — 'the Hebrew women are vigorous and give birth before the midwife arrives' — may be a tactful deflection rather than a literal claim, though it exploits a real characteristic of birth timing.</p>",
"19": "<p>The characterization of Hebrew women as <em>chayyot</em> — 'lively/vigorous' (the word also means animal-like in vitality, full of life) — is the midwives' cover story. Whether this is an outright lie or a strategic half-truth the narrative leaves ambiguous. Ancient rabbinic discussion engaged this question seriously, debating whether the midwives' deception was justified. The narrative evaluates them by their outcome (God blessed them, v.20) rather than analyzing the ethics of their statement — a pragmatic rather than prescriptive response to the moral complexity of unjust authority.</p>",
"20": "<p>God blessed the midwives and the people multiplied — the two effects of the midwives' faithful defiance. Divine blessing (<em>vayetev Elohim lamyaledot</em>) answers their act of courage with concrete flourishing. The multiplication of Israel is directly attributed to the midwives' refusal. Historical and theological agency intersect here: God's sovereign plan to increase Israel uses the free moral choice of two women to achieve what no divine intervention at the moment required. The ordinary courage of ordinary people becomes the mechanism of divine action.</p>",
"21": "<p>God gave the midwives households (<em>battim</em>) — families of their own. The midwives who preserved the lives of Israel's children received children (and family lines) of their own. The reward is proportionate: they gave life; they receive life. Some ancient interpreters identified Shiphrah and Puah with Jochebed and Miriam (or Zipporah), making them the mothers or family of Moses himself — an attractive but unverifiable connection.</p>",
"22": "<p>The decree extended to all Egyptians — every newborn Hebrew boy is to be thrown into the Nile. The genocide order is nationalized: not just the midwives but all Egyptian subjects are now enlisted as agents of destruction. The Nile — Egypt's source of life, the god Hapy's domain, the agricultural foundation of the civilization — becomes the instrument of infanticide. The irony runs deep: the river that gives Egypt its life is commanded to take Israel's life; but the same river will preserve Moses (ch.2) and ultimately become the first plague-target (Ex 7:20), turning life-giving water to blood.</p>"
},
"2": {
"1": "<p>A man of the house of Levi married a daughter of Levi — the specific names (Amram and Jochebed) are withheld here and revealed later (Ex 6:20; Num 26:59). The sparse genealogy focuses the reader on the event rather than the persons. The Levitical parentage of Moses is theologically significant: the future mediator of the covenant will come from the tribe that later receives the priestly office. Aaron (the first high priest) and Moses (the lawgiver/mediator) are brothers from the same tribe, positioning Levi as the tribe of both sacerdotal and prophetic mediation.</p>",
"2": "<p>She hid him for three months — the three-month concealment represents the limits of domestic resistance to state power. Under Pharaoh's decree, the birth of a male child required immediate action. The mother's act of hiding the child was an act of civil defiance, at personal risk. 'She saw that he was good' (<em>vatere oto ki-tov</em>) echoes the creation refrain of Gen 1 (<em>ki tov</em>) — the child's goodness is recognized with the same formula used when God saw the light and pronounced it good. The echo is not accidental: a new creation, a new beginning, is observed by a mother's eyes.</p>",
"3": "<p>The papyrus basket (<em>tevah</em> of <em>gome</em>) coated with bitumen and pitch — <em>tevah</em> is the same word used only twice in the OT: for Noah's ark (Gen 6-9) and for this basket. The parallel is structural: in both cases, a righteous individual is preserved in a vessel on threatening waters while the world outside is threatened with death. The materials — bitumen (<em>chemar</em>) and pitch (<em>zepheth</em>) — are the same waterproofing materials Noah used (Gen 6:14). The Nile becomes the flood; Moses becomes a new Noah; the bulrushes become the new Ararat. Egypt is the waters of chaos; the vessel carries the one through whom salvation will come.</p>",
"4": "<p>His sister (identified in Ex 15:20 as Miriam) stationed herself at a distance to observe — <em>letedah mah-yea'aseh lo</em>, to see what would happen to him. The sister's watchful presence is the hinge of the narrative: she observes, then initiates (v.7). Miriam, who will later lead Israel in song at the Reed Sea (Ex 15:20-21), here plays her first decisive role in the preservation of the deliverer. The narrative quietly assigns agency to an unnamed girl before the major characters have names.</p>",
"5": "<p>Pharaoh's daughter came down to bathe at the Nile — Egyptian queens and noblewomen are depicted in Egyptian art bathing in the Nile or in palace pools. The scene is historically plausible. The daughter of the man who ordered the genocide discovers the basket hidden among the reeds. Providence brings together the most vulnerable (a condemned infant) and the most powerful (a daughter of absolute power) at the same point in the river. She recognizes the child as a Hebrew infant — the very child her father's decree condemned — and chooses compassion over compliance.</p>",
"6": "<p>She had compassion on him (<em>vatachmol alav</em>) — <em>chamal</em> is the word for sparing or having pity, the same word used when Saul spared Agag (1 Sam 15:9) and when YHWH says 'should I not spare Nineveh' (Jonah 4:11). A daughter of the Pharaoh who commanded genocide spares the condemned child — the political order is undermined from within by the compassion of its own household. She identifies him immediately as a Hebrew child: no illusions, but compassion stronger than political calculation.</p>",
"7": "<p>Miriam steps forward and offers to find a Hebrew nursing woman — the initiative is swift and bold for a young girl addressing a princess. The offer is transparent in retrospect: the nurse will be the child's own mother. But the scene is presented with dramatic irony: Pharaoh's daughter accepts the offer, not knowing she is agreeing to reunite mother and child. The arrangement is providential: the decree of death is reversed by the decree of the powerful, through the initiative of the powerless.</p>",
"8": "<p>'Go' — Pharaoh's daughter authorizes Miriam with a single word. The girl fetches the child's own mother. The speed of the exchange and the lightness of the narrative conceal the enormity of what has happened: the infant condemned to death by Pharaoh's decree will be raised in Pharaoh's household, nursed by his own mother, at Pharaoh's expense. The very mechanism of oppression funds the upbringing of Israel's deliverer.</p>",
"9": "<p>'Take this child and nurse him for me, and I will give you your wages' — the irony is complete. Egypt will pay an Israelite mother to raise her own son within Pharaoh's court. The wages (<em>sakar</em>) that Egypt denied the enslaved Israelites (there is no record of payment for the building-project labor) are here given to the mother of the future deliverer. The reversal is personal before it becomes national: Jochebed is compensated by the household that oppressed her people.</p>",
"10": "<p>She named him Moses (<em>Mosheh</em>) — Egyptian: <em>msy</em> = 'born of' or 'son of' (as in Thutmoses = born of Thoth; Ramesses = born of Ra). The Egyptian name is given a Hebrew etymology: <em>ki min-hammayim meshitihu</em> — 'for I drew him out of the water' (from <em>mashah</em> = to draw out). Both etymologies are at play: the Egyptian child of the palace, and the Hebrew child drawn from the water. Acts 7:22 adds that Moses was educated in all the wisdom of the Egyptians — palace education in the New Kingdom included language, administration, military training, religious knowledge, and scribal arts. Forty years of Egyptian formation prepares him for forty years of wilderness and forty years of leadership.</p>",
"11": "<p>Moses grew up and went out to his brothers — the narrative compresses forty years into a phrase. The transition from palace to people is an act of identification: Moses chooses to look at the burden (<em>sivelotam</em>) of his people. He kills an Egyptian taskmaster who was beating a Hebrew. The killing is done in secret — he looks 'this way and that' — which reveals both the clandestine nature of the act and its moral ambiguity. Moses is not yet a deliverer but a man acting on impulse; his individual act of justice cannot deliver the people and nearly destroys him. The gap between the private act and public mandate is the gap the burning bush will bridge.</p>",
"12": "<p>He hid the Egyptian in the sand — the concealment anticipates the next day's reversal when the act becomes known. Desert sand was used for hasty burials in antiquity, and Egypt's desert environment made such concealment possible. The image is not heroic: Moses is covering his tracks, not leading a revolution. The narrative is honest about the unsanctioned, impulsive, ineffective nature of Moses' first intervention — the contrast with the commissioned deliverer of ch.3 is stark.</p>",
"13": "<p>Two Hebrews fighting — Moses intervenes again, challenging the one in the wrong. The response — 'Who made you a prince and a judge over us?' — is devastating in its logic: Moses has no authority, no commission, no recognized standing among his own people. The question echoes forward in Israel's history: the prophet without honor among his own (cf. Luke 4:24), the sent one rejected by those he was sent to serve. Stephen cites this exact moment in Acts 7:27, 35 as the prototype of Israel's rejection of its own deliverer — a pattern he traces from Moses to Jesus.</p>",
"14": "<p>'Did you intend to kill me as you killed the Egyptian?' — the act is known. The network of enslaved people was apparently more observant than Moses realized; secrets in a slave community are not secrets for long. The exposure of the killing and the rebuff from his own people collapse Moses' nascent project. He is now a wanted man in Egypt, rejected by the people he tried to help, without a home in either world. The social destruction is complete: he cannot return to Pharaoh's court, and he cannot lead the Hebrews. The only direction is out.</p>",
"15": "<p>Moses fled to Midian — Midian is the territory east and southeast of the Sinai, in the northwestern Arabian Peninsula (modern northwest Saudi Arabia and southern Jordan). The Midianites were descendants of Abraham through Keturah (Gen 25:1-2), making them distant kin of the Israelites with a shared Abrahamic heritage. The journey from the eastern Nile delta to Midian through the Sinai Peninsula was a trek of several weeks through desert terrain. Moses arrives as a fugitive and sits by a well — the well scene immediately invokes the patriarchal type-scene: Abraham's servant meets Rebekah at a well (Gen 24), Jacob meets Rachel at a well (Gen 29). The reader expects a marriage to follow.</p>",
"16": "<p>The priest of Midian (identified as Reuel here, as Jethro in Ex 3:1 and elsewhere — possibly two names, a personal name and a title/honorific) had seven daughters. Reuel means 'friend of God' (<em>re'u-El</em>). A Midianite priest with this name suggests the Midianites had some knowledge of El, the high God of the Semitic world. The seven daughters are shepherdesses — their presence at a public well for watering flocks is a normal pastoral scene. Seven is the number of completeness; the arrival of seven daughters at the well creates a scene of providential abundance.</p>",
"17": "<p>Shepherds drove the daughters away — the social dynamic is familiar in the ancient world: male shepherds asserting priority at a shared water source at the expense of women. Moses' intervention is immediate: he rose to their defense and watered their flock. The same protective instinct that killed the Egyptian taskmaster is here channeled constructively — a small act of justice at a foreign well. The contrast with the Egyptian incident is instructive: the same impulse, in a proportionate and non-lethal context, produces a good outcome. Moses is not an unjust man; he is a man whose justice needs a proper channel.</p>",
"18": "<p>'Why have you come home so early today?' — Reuel's question establishes the daughters' normal pattern: the well was a contested space where they were regularly delayed. Moses' intervention was noteworthy precisely because it reversed the usual social dynamic. Reuel's response to the account — 'Where is he? Why did you leave the man?' — reflects the Middle Eastern hospitality ethic: the stranger who has done a good deed must be brought in and fed. The invitation to eat is the beginning of Moses' forty-year residency in Midian.</p>",
"19": "<p>'An Egyptian man delivered us from the hand of the shepherds' — Zipporah and her sisters identify Moses as Egyptian, not Hebrew. Forty years in Pharaoh's court had given Moses the appearance, language, and dress of an Egyptian. His identity is visibly ambiguous: born Hebrew, raised Egyptian, fled to Midian. This triple alienation — belonging fully to no nation — is not a tragedy but a formation. The man who will stand between Pharaoh and Israel, mediating between two peoples, must be at home in neither world and known to both.</p>",
"20": "<p>Reuel's hospitality invitation follows the ancient Near Eastern pattern: the stranger must not be allowed to remain unfed. The principle of hospitality to strangers (<em>hachnasat orchim</em> in later Jewish thought) was a fundamental social obligation in desert cultures where travelers were entirely dependent on the goodwill of settled households. Reuel's invitation is culturally instinctive and narratively providential: the man who will one day bring Israel to meet YHWH at Sinai first meets YHWH's people through a priestly household's table.</p>",
"21": "<p>Moses agreed to dwell with the man and was given Zipporah (<em>Tzipporah</em> = bird, H6855) as his wife. The marriage follows the patriarchal pattern: the stranger who proves himself at a foreign well marries into the local family (Jacob married Rachel after demonstrating his strength at the well in Gen 29:10-11). Moses' marriage to a Midianite connects him to the semi-nomadic pastoral world that was the original social environment of the patriarchs. Zipporah's significance extends beyond this chapter: she will play a decisive role in Ex 4:24-26 (the circumcision crisis), and her voice and actions matter in the narrative.</p>",
"22": "<p>Gershom — Moses named his son 'stranger there' (<em>ger sham</em>), explaining: 'I have been a stranger in a foreign land.' The name encapsulates Moses' identity crisis: he is a Hebrew who was an Egyptian who is now in Midian. The word <em>ger</em> (stranger/sojourner) becomes one of the most important categories in Israelite law — the stranger who lives among you must be treated justly, 'for you were strangers in Egypt' (Ex 22:21, 23:9; Lev 19:34; Deut 10:19). Moses' forty years as a <em>ger</em> in Midian form him in the experience that will ground Israel's ethics of stranger-care.</p>",
"23": "<p>During that long period — forty years pass. The king of Egypt died (whether Thutmose III, Seti I, or another depends on the dating). The Israelites groaned and cried out (<em>vayiz'aqu</em> — the legal term for a cry of appeal before a judge or authority). Their cry went up to God — the language is judicial: a formal complaint reaching the divine court. This is not merely prayer but a legal appeal. In the ANE, the oppressed could appeal to the king for justice; the Israelites, having no human king to appeal to, cry out to the divine judge. The cry is heard (v.24).</p>",
"24": "<p>God heard (<em>shama</em>), God remembered (<em>zakar</em>) his covenant with Abraham, Isaac, and Jacob. The covenant memory of YHWH is not passive recollection but active initiation — in Hebrew thought, to remember is to act on what is remembered. God's remembering of the patriarchal covenant is the theological engine of the Exodus: Israel is not delivered because it deserves it, but because God made a promise to the fathers and is faithful to his word. The triple invocation of Abraham, Isaac, and Jacob recurs throughout Exodus and becomes the foundational formula of Israelite prayer.</p>",
"25": "<p>God saw Israel (<em>vayyar</em>), and God knew (<em>vayyeda</em>). The four verbs across vv.24-25 — heard, remembered, saw, knew — constitute a fourfold statement of divine attention. <em>Yada</em> here is covenantal knowing, not mere cognitive awareness: the same word used for intimate relational knowledge (Gen 4:1), for YHWH knowing Moses face to face (Deut 34:10), for the elect being foreknown (Amos 3:2). God does not merely observe Israel's suffering from a distance; he acknowledges it with covenant commitment. The Exodus is the consequence of these four acts of divine attention.</p>"
},
"3": {
"1": "<p>Moses was tending the flock of Jethro his father-in-law, the priest of Midian — the same man called Reuel in 2:18 (Reuel as personal name, Jethro as title or second name meaning 'his excellence/abundance'). The back of the desert (<em>achar hammidbar</em>) — the far side, the uninhabited interior. Moses leads the flock to Horeb, the mountain of God. Horeb (= Sinai) is the narrator's prospective identification; Moses does not know the mountain's name yet. The traditional location is Jebel Musa in the southern Sinai Peninsula (ca. 2,285m), though an alternative tradition places it in the Hejaz in northwestern Saudi Arabia (Jebel al-Lawz). What the text establishes is the setting: the far wilderness, away from human settlement, where only isolation and silence allow divine encounter.</p>",
"2": "<p>The angel of YHWH (<em>malach YHWH</em>) appeared to him in a flame of fire from within the bush. The bush is <em>sneh</em> — a thorny shrub, likely a type of acacia or bramble common in the Sinai desert. It burns but is not consumed. Fire is the consistent OT marker of divine presence: the pillar of fire (Ex 13:21), the fire on Sinai (Ex 19:18), the fire that consumed Elijah's offering (1 Kings 18:38), the coal from the altar at Isaiah's commissioning (Isa 6:6-7). The non-consuming fire distinguishes divine fire from ordinary destruction: holiness burns without consuming, illuminates without destroying — precisely the characteristic that will define the divine relationship with Israel.</p>",
"3": "<p>'I will turn aside and see this great sight — why the bush is not burned up.' Moses is a trained observer: a former Egyptian administrator and a shepherd, both roles requiring attention to anomalies. His curiosity is the prerequisite for encounter. The bush does not compel; it invites. The divine communication requires a willing turn, a decision to investigate. This structure — the divine initiative that awaits human response — is characteristic of YHWH's mode of encounter throughout the OT (cf. Elijah at the still small voice in 1 Kings 19:12-13).</p>",
"4": "<p>'Moses, Moses' — the doubled name signals divine urgency and personal intimacy, a rhetorical pattern shared with Abraham at the Aqedah (Gen 22:11: 'Abraham, Abraham'), Samuel's first call (1 Sam 3:10: 'Samuel, Samuel'), and later Paul on the Damascus road (Acts 9:4: 'Saul, Saul'). The double naming distinguishes this call from ordinary speech. 'Here I am' (<em>hineni</em>) — the response of complete availability, the same word Abraham uses at the Aqedah, Isaiah at his commissioning (Isa 6:8). The response before the command: readiness declared before the demand is made.</p>",
"5": "<p>'Take off your sandals, for the place where you are standing is holy ground (<em>admat qodesh</em>).' The removal of sandals signals that the wearer stands on ground that belongs to another — an act of submission and vulnerability (bare feet on sacred soil). The ground is holy not by nature but by presence: YHWH's presence sanctifies it. This principle runs throughout the tabernacle legislation and into temple theology. The same instruction is given to Joshua at Jericho (Josh 5:15) — both commissions begin with the removal of sandals before the divine commander. The practice of removing shoes before holy spaces is preserved in Jewish, Islamic, and some Christian traditions.</p>",
"6": "<p>'I am the God of your father, the God of Abraham, the God of Isaac, and the God of Jacob.' The self-identification connects the Mosaic commission directly to the patriarchal covenant. Moses' generation had not experienced YHWH directly — the divine name had not been made known in its fullness (Ex 6:3 implies the patriarchs knew God as El Shaddai, not YHWH). The introduction grounds the new commission in the old covenant: this is not a new god but the God of the fathers. Moses hides his face — a standard response to theophany throughout the OT (cf. Isa 6:2 — the seraphim cover their faces; Ex 33:20 — no one can see YHWH's face and live). Jesus cites this verse in Mark 12:26-27 to argue for resurrection: the present-tense claim — 'I am the God of Abraham' — implies Abraham is presently alive before God.</p>",
"7": "<p>'I have surely seen the affliction of my people in Egypt, and have heard their cry because of their taskmasters. I know their sufferings.' The four verbs of divine attention from 2:24-25 are now given as direct divine speech. <em>Yad'ati</em> (I know) — the covenantal knowing of 2:25 becomes a spoken commitment. The three-fold statement (seen, heard, know) is the divine's formal acknowledgment of Israel's legal complaint. In ANE thought, when a suzerain acknowledges a vassal's appeal, it obligates the suzerain to act. YHWH's acknowledgment of Israel's cry is the basis for the mission that follows: I have seen, therefore I am sending.</p>",
"8": "<p>'I have come down to deliver them from the hand of the Egyptians and to bring them up out of that land to a good and broad land, a land flowing with milk and honey.' The divine descent to deliver — <em>vareed lehatzilo</em> — is incarnational language: the transcendent God comes down to act in history. 'Milk and honey' is a formulaic description of agricultural and pastoral abundance: milk from flocks (pastoral economy), honey from bees feeding on flowering vegetation (agricultural ecosystem). The six nations listed — Canaanites, Hittites, Amorites, Perizzites, Hivites, Jebusites — are the standard pre-conquest inventory found throughout Deuteronomy and Joshua, a formulaic list that the Israelite audience would have recognized as the catalog of Canaan's inhabitants.</p>",
"9": "<p>The cry of the Israelites has reached YHWH — the legal appeal of 2:23 is formally received at the divine court. The vocabulary is judicial: the oppression (<em>lachatz</em> = pressing down, oppression) of the Egyptians is presented as the grounds for a legal finding in Israel's favor. The divine judge has heard the appeal; the remedy is deliverance. This judicial framework for the Exodus is foundational to Israel's understanding of YHWH as judge and advocate of the powerless — a theme that runs through the Psalms, the prophets, and into the NT language of justification.</p>",
"10": "<p>'Come now, I will send you to Pharaoh that you may bring my people, the children of Israel, out of Egypt.' The commissioning formula. The word <em>shalacha</em> (I will send) is the verb from which <em>shaliach</em> (sent one, emissary, apostle) derives. Moses is not a volunteer but a <em>shaliach</em> — sent with authority, speaking in the name of the one who sent him. The NT apostolate (Greek <em>apostolos</em> = sent one) operates on this same legal principle: the one sent speaks with the authority of the sender and is to be received as the sender himself (cf. John 13:20: 'whoever receives the one I send receives me').</p>",
"11": "<p>'Who am I that I should go to Pharaoh and bring the children of Israel out of Egypt?' — Moses' first objection. The question is not false modesty but accurate self-assessment: he is a fugitive, an ex-administrator with no current standing, unknown to the current Pharaoh and distrusted by the Hebrews (2:14). The divine answer to the identity question is not a résumé but a promise: 'I will be with you (<em>ehyeh imach</em>).' The commission rests not on Moses' qualifications but on divine accompaniment. This pattern — God choosing the unlikely and promising his presence — recurs with Gideon (Judges 6:12-16), Jeremiah (Jer 1:6-8), and Paul (2 Cor 12:9-10).</p>",
"12": "<p>'This shall be the sign for you' — the sign is paradoxical: when you bring the people out, you will serve God on this mountain. Most biblical signs precede the action they confirm; this sign follows it. Moses cannot verify the sign before he acts — only after the mission succeeds will the sign become visible. This structure demands faith: trust the promise before the evidence arrives. The mountain is the same ground where Moses now stands; the pilgrimage to Sinai after the exodus is therefore already embedded in the commission. Sinai is not an accidental destination but the pre-announced goal of the exodus itself.</p>",
"13": "<p>Moses' second objection: What is his name? The question anticipates the community's question — by whose authority do you come? In the ancient world, the name of a deity was not a label but a compressed disclosure of character, power, and covenant relationship. To act in the name of a god was to invoke that god's authority and stake the mission on that god's reputation. Moses needs more than 'the God of your fathers' — he needs a name that can be invoked in Pharaoh's court and believed by enslaved Israelites. The divine response to this request is the most important theological moment in the Torah.</p>",
"14": "<p>'Ehyeh asher ehyeh' — 'I AM WHO I AM' or 'I WILL BE WHAT I WILL BE.' The divine name is derived from the Hebrew root <em>hayah</em> (to be, to become, to be present). The form is imperfect — ongoing, unfinished — which gives it both an ontological meaning (I am absolute, unconditioned being) and a promissory meaning (I will be present in every future moment of need). The name cannot be fully translated because it asserts something about God that no human language was designed to express: self-existence, the ground of all being, the one who depends on nothing outside himself for his existence. This is the theological center of the OT doctrine of God, and the 'I am' statements of John's Gospel (<em>ego eimi</em>) are deliberate invocations of this divine name.</p>",
"15": "<p>YHWH — the sacred Tetragrammaton, the covenant name of God. 'This is my name forever, and this is my memorial-name throughout all generations.' The name YHWH is proprietary to Israel's covenant relationship — it is not the generic divine name (<em>Elohim</em>, El) used across the ancient world, but the personal name by which Israel's God distinguishes himself. Second Temple Jews developed the practice of not pronouncing the Tetragrammaton, substituting <em>Adonai</em> (Lord) in reading — a practice reflected in most English Bible translations where YHWH appears as LORD. The name's revelation to Moses at Sinai is the moment Israel's distinctive covenant knowledge of God begins.</p>",
"16": "<p>The elders of Israel (<em>zeqenim</em> — the elders) are the tribal leaders and heads of households who constituted Israel's pre-monarchic governance structure. During the Egyptian oppression, when there was no king and no formal government, the elders functioned as the representative body of the people. Moses is instructed to convene this body — his mission requires community authorization, not just divine commission. The assembly of elders is the legitimate political process through which the Exodus initiative will move from divine command to community action.</p>",
"17": "<p>'I will bring you up out of the affliction of Egypt, to the land of the Canaanites...' — the promise recapitulates the Abrahamic covenant (Gen 15:18-21) and the Sinai promise of v.8. The six nations are listed again (Canaanites, Hittites, Amorites, Perizzites, Hivites, Jebusites) — the same catalog as v.8. The formulaic repetition is deliberate: the elders of Israel need to hear the exact promise God made so they can recognize its fulfillment. The covenant vocabulary ('I promised') formally connects this moment to the patriarchal promises Moses is sent to fulfill.</p>",
"18": "<p>The request to Pharaoh: 'Let us go a three-day journey into the wilderness to sacrifice to YHWH our God.' The initial demand is for a temporary departure for religious observance — not permanent exodus. Whether this represents a genuine first step in a negotiation (with full freedom as the ultimate goal) or a modest opening bid, it serves the narrative function of establishing that Pharaoh's refusal is not a response to an unreasonable demand. Even the minimum request (a three-day pilgrimage festival) will be refused, making Pharaoh's intransigence the basis for the escalating plagues.</p>",
"19": "<p>YHWH predicts that Pharaoh will not let Israel go 'except by a mighty hand (<em>yad chazaqah</em>).' The strong hand of YHWH — <em>yad chazaqah</em> — becomes the signature phrase of the Exodus event, appearing over twenty times in Exodus and Deuteronomy. The Shema context in Deut 6:20-21 makes the strong hand the answer to the child's question: 'What do these statutes mean?' — 'We were slaves in Egypt and YHWH brought us out with a strong hand.' The phrase becomes the central confession of Israel's delivered identity: who we are is defined by whose hand brought us out.</p>",
"20": "<p>'I will stretch out my hand and strike Egypt with all my wonders' — the plagues are here announced as a unified divine action before any individual plague is described. The wonders (<em>niflaot</em>) will target Egypt's economic and ecological foundations: the Nile (blood), the land (frogs, gnats, flies), the livestock, the human body (boils), the sky (hail, darkness), and finally the firstborn. Each plague is calibrated to demonstrate YHWH's sovereignty over the specific domains Egypt's gods claimed to control (Hapy the Nile god, Khepri the beetle/frog god, Ra the sun god, etc.).</p>",
"21": "<p>The Egyptians will give Israel 'favor' (<em>chen</em>) in their sight — the word <em>chen</em> (grace/favor) is the same used when Joseph found favor with Potiphar and the jailer (Gen 39:4, 21). YHWH will cause the Egyptians to look favorably on the Israelites — a reversal of the contempt that fueled the oppression. The requesting of silver, gold, and clothing from Egyptian neighbors (v.22) is the mechanism of this favor.</p>",
"22": "<p>Every Israelite woman will ask her Egyptian neighbor for silver and gold jewelry and clothing — and will put them on her sons and daughters. 'You will plunder Egypt (<em>ventsaltem et-Mitzraim</em>).' The vocabulary is that of military plunder: the defeated city is stripped of its valuables by the victors. But Israel leaves not by military conquest but by divine decree, and the 'plunder' is the unpaid wages of centuries of forced labor. This motif was anticipated in the Abrahamic covenant (Gen 15:14: 'afterward they will come out with great possessions'), and its fulfillment in Ex 12:35-36 is the closing of a promise made four centuries earlier. The centuries of unpaid labor are settled in a single night.</p>"
}
}

def main():
    data = load_comm('mkt-context', 'exodus')
    merge_comm(data, EXODUS)
    save_comm('mkt-context', 'exodus', data)

    import json as _json
    il = _json.load(open(ROOT / 'data' / 'interlinear' / 'exodus.json'))
    all_ok = True
    for ch in ['1', '2', '3']:
        il_vv = set(il.get(ch, {}).keys())
        out_vv = set(data.get(ch, {}).keys())
        missing = il_vv - out_vv
        if missing:
            print(f'ch {ch} STILL MISSING: {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'ch {ch}: complete ({len(out_vv)} verses)')
    if all_ok:
        print('All verses present')

if __name__ == '__main__':
    main()
